func NewMuxer(
	listener net.Listener,
	vhostFunc muxFunc,
	timeout time.Duration,
) (mux *Muxer, err error) {
	mux = &Muxer{
		listener:	listener,
		timeout:	timeout,
		vhostFunc:	vhostFunc,
		registryRouter:	NewRouters(),
	}
	go mux.run()
	return mux, nil
}
